import { Component, signal, inject } from '@angular/core';
import { CommonModule } from '@angular/common';
import { RouterLink, Router } from '@angular/router';
import { ReactiveFormsModule, FormBuilder, Validators, FormArray, FormGroup } from '@angular/forms';
import { Supplier, Product } from '../../core/models';

@Component({
  selector: 'app-po-new',
  standalone: true,
  imports: [CommonModule, RouterLink, ReactiveFormsModule],
  templateUrl: './po-new.component.html',
})
export class PoNewComponent {
  private fb = inject(FormBuilder);
  private router = inject(Router);

  suppliers = signal<Supplier[]>([
    { id: 's1', name: 'Acme Industrial Supply', contactName: 'Jane Cole', email: 'sales@acme.example' },
    { id: 's2', name: 'Globex Materials', contactName: 'Ravi Patel', email: 'orders@globex.example' },
  ]);

  products = signal<Product[]>([
    { id: 'p1', sku: 'STL-001', name: 'Steel Bolt M8', cost: 0.45, price: 1.20, onHand: 1200 },
    { id: 'p3', sku: 'PIP-050', name: 'PVC Pipe 50mm', cost: 3.20, price: 7.50, onHand: 340 },
    { id: 'p7', sku: 'PNL-100', name: 'Control Panel', cost: 145.00, price: 320.00, onHand: 18 },
  ]);

  form = this.fb.group({
    supplier: ['', Validators.required],
    lines: this.fb.array([this.createLine()]),
  });

  get lines(): FormArray {
    return this.form.get('lines') as FormArray;
  }

  private createLine(): FormGroup {
    return this.fb.group({
      product: ['', Validators.required],
      qty: [1, [Validators.required, Validators.min(1)]],
    });
  }

  addLine(): void {
    this.lines.push(this.createLine());
  }

  removeLine(i: number): void {
    this.lines.removeAt(i);
  }

  estimatedTotal(): number {
    return this.lines.controls.reduce((sum, ctrl) => {
      const productId = ctrl.get('product')?.value;
      const qty = Number(ctrl.get('qty')?.value) || 0;
      const product = this.products().find((p) => p.id === productId);
      return sum + (product ? product.cost * qty : 0);
    }, 0);
  }

  submit(): void {
    if (this.form.invalid) {
      this.form.markAllAsTouched();
      return;
    }
    this.router.navigate(['/purchase-orders']);
  }
}
